const input = $input.first().json;
const {topic, project, avatar, pass_number, research_brief} = input;
const SB = $env.SUPABASE_URL, SRK = $env.SUPABASE_SERVICE_ROLE_KEY, AK = $env.ANTHROPIC_API_KEY;
const PASS = pass_number || 1;
const WT = PASS === 2 ? '8,000-10,000 words' : '5,000-7,000 words';
const MIN_WORDS = PASS === 2 ? 8000 : 5000;
const MAX_WORDS = PASS === 2 ? 10000 : 7000;
const MAX = 3;

async function gp(t) {
  const r = await fetch(SB + '/rest/v1/system_prompts?prompt_type=eq.' + t + '&is_active=eq.true&select=prompt_text', {headers: {'apikey': SRK, 'Authorization': 'Bearer ' + SRK}});
  return ((await r.json())?.[0]?.prompt_text) || '';
}

async function cc(s, u, m) {
  var maxRetries = 3;
  var lastErr = null;
  for (var attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      var b = {model: 'claude-sonnet-4-20250514', max_tokens: m || 64000, messages: [{role: 'user', content: u}]};
      if (s) b.system = s;
      var r = await fetch('https://api.anthropic.com/v1/messages', {method: 'POST', headers: {'Content-Type': 'application/json', 'x-api-key': AK, 'anthropic-version': '2023-06-01'}, body: JSON.stringify(b)});
      if (r.status === 429) {
        console.log('Rate limited (attempt ' + attempt + '), waiting 30s...');
        await new Promise(function(res) { setTimeout(res, 30000); });
        continue;
      }
      if (r.status === 529) {
        console.log('API overloaded (attempt ' + attempt + '), waiting 15s...');
        await new Promise(function(res) { setTimeout(res, 15000); });
        continue;
      }
      var d = await r.json();
      if (d.error) throw new Error('Claude: ' + JSON.stringify(d.error));
      return (d.content || []).filter(function(c) { return c.type === 'text'; }).map(function(c) { return c.text; }).join('');
    } catch (e) {
      lastErr = e;
      console.log('cc() attempt ' + attempt + ' failed: ' + e.message);
      if (attempt < maxRetries) {
        var wait = Math.min(10000 * Math.pow(2, attempt - 1), 60000);
        console.log('Retrying in ' + (wait/1000) + 's...');
        await new Promise(function(res) { setTimeout(res, wait); });
      }
    }
  }
  throw lastErr || new Error('cc() failed after ' + maxRetries + ' attempts');
}

function fi(t, v) {
  let r = t;
  for (const [k, val] of Object.entries(v)) r = r.split('{' + k + '}').join(val || '');
  return r;
}

const [sysTpl, passTpl, evalTpl, retryTpl] = await Promise.all([
  gp('script_system_prompt'), gp('script_pass' + PASS), gp('script_evaluator'), gp('script_retry_template')
]);

const v = {
  subtopic: topic.seo_title || topic.original_title || '',
  niche_category: project.niche || '',
  target_audience_segment: topic.target_audience_segment || '',
  audience_avatar: avatar?.audience_avatar || avatar?.avatar_name_age || '',
  psychographics: topic.psychographics || '',
  key_emotional_drivers: topic.key_emotional_drivers || '',
  viewer_search_intent: topic.viewer_search_intent || '',
  core_domain_framework: topic.core_domain_framework || '',
  primary_problem_trigger: topic.primary_problem_trigger || '',
  content_angle_blue_ocean: topic.content_angle_blue_ocean || '',
  video_style_structure: topic.video_style_structure || '',
  practical_takeaways: topic.practical_takeaways || ''
};

if (PASS === 2) v.PASS_1_OUTPUT = input.pass1_output || '';

const sp = fi(sysTpl, v);
let origP = fi(passTpl, v);

if (PASS === 3) {
  origP = origP.replace(/\{PASS_1_SUMMARY[^}]*\}/g, input.pass1_summary || '');
  origP = origP.replace(/\{PASS_2_SUMMARY[^}]*\}/g, input.pass2_summary || '');
  origP = origP.replace(/\{CHARACTER_NAME\}/g, input.character_name || '');
  origP = origP.replace(/\{1-sentence[^}]*\}/g, input.character_status || '');
  origP = origP.replace(/\{LIST_OF_METAPHORS[^}]*\}/g, (input.metaphors_used || []).join(', '));
  origP = origP.replace(/\{LIST\s*\u2014[^}]*\}/g, (input.reassurance_phrases || []).join(', '));
  origP = origP.replace(/\{LIST_OF_NOTABLE_PHRASES[^}]*\}/g, (input.notable_phrases || []).join(', '));
}

const intelligence_block = input.intelligence_block || '';

const RESEARCH_PREFIX = (research_brief && research_brief.length > 50)
  ? research_brief + '\n\n=== MANDATORY: Your script MUST address the audience demands, blue ocean opportunities, and 10x strategies described above. Weave them naturally into the narrative. Do NOT ignore this research data. ===\n\n'
  : '';

const WC_PREFIX = '=== ABSOLUTE WORD COUNT REQUIREMENT ===\n'
  + 'Your output MUST contain between ' + MIN_WORDS + ' and ' + MAX_WORDS + ' words of spoken narration.\n'
  + 'This is a HARD requirement. Outputs under ' + MIN_WORDS + ' words are automatically rejected.\n'
  + 'Write in full, expanded detail. Develop every section thoroughly with extended scenes, specific examples, and detailed explanations.\n'
  + 'DO NOT wrap up early. If you feel the urge to conclude, you are NOT done \u2014 continue writing.\n'
  + '=== END REQUIREMENT ===\n\n';

let att = 0, up = origP, res = null;

while (att < MAX) {
  att++;
  const INTEL_PREFIX = intelligence_block ? intelligence_block + '\n\n' : '';
  const pt = await cc(sp, INTEL_PREFIX + RESEARCH_PREFIX + WC_PREFIX + up, 64000);
  if (!pt || pt.length < 500) {
    if (att >= MAX) { res = {pass_text: pt || '', scores: {}, composite_score: 0, verdict: 'FORCE_PASS', attempt: att, word_count_estimate: 0, manual_review_flag: true}; break; }
    continue;
  }

  const wc = pt.split(/\s+/).length;
  console.log('Pass ' + PASS + ' attempt ' + att + ': ' + wc + ' words (target: ' + MIN_WORDS + '-' + MAX_WORDS + ')');

  if (wc < MIN_WORDS * 0.7 && att < MAX) {
    console.log('Word count ' + wc + ' below floor (' + Math.floor(MIN_WORDS * 0.7) + '). Skipping eval, retrying with expansion.');
    up = 'WORD COUNT FAILURE: Your previous output was only ' + wc + ' words. The MINIMUM required is ' + MIN_WORDS + ' words.\n\n'
      + 'Below is your previous output. EXPAND it to at least ' + MIN_WORDS + ' words by adding more detail, longer scenes, more examples, and more thorough explanations to every section. Keep the same structure and style. Do not rewrite from scratch \u2014 expand what you wrote.\n\n'
      + '--- YOUR PREVIOUS OUTPUT (' + wc + ' WORDS) ---\n'
      + pt + '\n'
      + '--- END PREVIOUS OUTPUT ---\n\n'
      + 'EXPAND the above to AT LEAST ' + MIN_WORDS + ' words. Make every section longer and more detailed.';
    continue;
  }

  const ep = fi(evalTpl, {subtopic: v.subtopic, niche_category: v.niche_category, PASS_NUMBER: String(PASS), WORD_TARGET_FOR_THIS_PASS: WT, ATTEMPT_NUMBER: String(att), PASS_OUTPUT: pt});
  const et = await cc(null, ep, 4096);
  let ev;
  try {
    const c = et.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
    ev = JSON.parse(c.substring(c.indexOf('{'), c.lastIndexOf('}') + 1));
  } catch (e) {
    ev = {composite_score: 5, verdict: att >= MAX ? 'FORCE_PASS' : 'FAIL_RETRY', failures: ['parse_error'], retry_guidance: 'Eval parse failed', word_count_estimate: pt.split(/\s+/).length, scores: {}};
  }
  if (att >= MAX && ev.verdict !== 'PASS') ev.verdict = 'FORCE_PASS';
  if (ev.verdict === 'PASS' || ev.verdict === 'FORCE_PASS') {
    res = {pass_text: pt, scores: ev.scores || {}, composite_score: ev.composite_score || 0, verdict: ev.verdict, attempt: att, word_count_estimate: ev.word_count_estimate || wc, manual_review_flag: ev.verdict === 'FORCE_PASS' && (ev.composite_score || 0) < 5, failures: ev.failures || []};
    break;
  }
  up = fi(retryTpl, {ATTEMPT_NUMBER: String(att + 1), COMPOSITE_SCORE: String(ev.composite_score || 0), FAILURES_LIST: (ev.failures || []).join(', '), RETRY_GUIDANCE_FROM_EVALUATOR: ev.retry_guidance || '', WORD_COUNT_ESTIMATE: String(ev.word_count_estimate || 0), WORD_TARGET_FOR_THIS_PASS: WT, ORIGINAL_PASS_PROMPT: origP});
  if ((ev.failures || []).includes('word_count_compliance') || wc < MIN_WORDS) {
    up += '\n\n--- YOUR PREVIOUS OUTPUT (' + wc + ' WORDS \u2014 MUST REACH ' + MIN_WORDS + '+) ---\n' + pt + '\n--- END ---\n\nEXPAND the above to at least ' + MIN_WORDS + ' words. Add more detail to every section.';
  }
}

if (!res) res = {pass_text: '', scores: {}, composite_score: 0, verdict: 'FORCE_PASS', attempt: MAX, word_count_estimate: 0, manual_review_flag: true};

try {
  await fetch(SB + '/rest/v1/production_logs', {method: 'POST', headers: {'apikey': SRK, 'Authorization': 'Bearer ' + SRK, 'Content-Type': 'application/json'}, body: JSON.stringify({project_id: project.id, topic_id: topic.id, stage: 'script_pass_' + PASS, action: res.verdict.toLowerCase(), details: {attempt: res.attempt, composite_score: res.composite_score, word_count: res.word_count_estimate}})});
} catch (e) {}

return [{json: {...res, pass_number: PASS, research_brief: research_brief || ''}}];
